import React, { Component } from 'react';
import io from 'socket.io-client';
import { getWiFiInfoTranslations, applyDisplayI18nConfig } from '../../config/displayTranslations.js';
// Styles are loaded from /css/styles.css (compiled.scss from backend)

class WiFiInfo extends Component {
  constructor(props) {
    super(props);
    this.state = {
      loading: true,
      error: null,
      ssid: '',
      password: '',
      logoLightUrl: '/img/logo.W.png',
      i18nTick: 0
    };
    this.socket = null;
  }

  componentDidMount() {
    // Load i18n config so admin translation overrides take effect
    this.loadI18nConfig();

    this.loadWiFiInfo();
    this.loadLogoConfig();
    
    // Connect to Socket.IO for real-time updates
    this.socket = io();
    
    // Listen for WiFi config updates
    if (this.socket && this.socket.on) {
      this.socket.on('wifiConfigUpdated', (config) => {
        console.log('WiFi config updated via Socket.IO:', config);
        this.setState({
          ssid: config.ssid || '-',
          password: config.password || '-',
          loading: false
        });
        
        // Force QR code image reload
        const qrImage = document.querySelector('.wifi-qr-container img');
        if (qrImage) {
          qrImage.src = `/img/wifi-qr.png?t=${Date.now()}`;
        }
      });
      
      // Listen for logo config updates
      this.socket.on('logoConfigUpdated', (config) => {
        console.log('Logo config updated via Socket.IO:', config);
        this.setState({
          logoLightUrl: config.logoLightUrl || '/img/logo.W.png'
        });
      });

      // Listen for i18n config updates
      this.socket.on('i18nConfigUpdated', (i18nConfig) => {
        applyDisplayI18nConfig(i18nConfig);
        this.setState({ i18nTick: Date.now() });
      });
    }
    
    // Reload every 30 seconds as backup
    this.interval = setInterval(() => {
      this.loadWiFiInfo();
      this.loadLogoConfig();
    }, 30000);
    
    // Set page title
    const t = this.getTranslations();
    document.title = t.title;
  }

  componentWillUnmount() {
    if (this.interval) {
      clearInterval(this.interval);
    }
    if (this.socket) {
      this.socket.disconnect();
    }
  }

  loadWiFiInfo = () => {
    fetch('/api/wifi')
      .then(response => response.json())
      .then(data => {
        this.setState({
          loading: false,
          ssid: data.ssid || '-',
          password: data.password || '-'
        });
      })
      .catch(err => {
        this.setState({
          loading: false,
          error: err.message
        });
      });
  }

  loadLogoConfig = () => {
    fetch('/api/logo')
      .then(response => response.json())
      .then(data => {
        this.setState({
          logoLightUrl: data.logoLightUrl || '/img/logo.W.png'
        });
      })
      .catch(err => {
        console.error('Error loading logo config:', err);
      });
  }

  loadI18nConfig = () => {
    fetch('/api/i18n')
      .then(response => response.json())
      .then(data => {
        applyDisplayI18nConfig(data);
        this.setState({ i18nTick: Date.now() });
        // Update page title with potentially overridden translation
        const t = this.getTranslations();
        document.title = t.title;
      })
      .catch(err => {
        console.error('Error loading i18n config:', err);
      });
  }

  getTranslations() {
    return getWiFiInfoTranslations();
  }

  render() {
    const { loading, error, ssid, password, logoLightUrl } = this.state;
    const t = this.getTranslations();

    return (
      <div className="wifi-page">
        <div className="wifi-container">
          <div className="wifi-logo">
            <img src={logoLightUrl} alt="Logo" onError={(e) => { e.target.src = '/img/logo.W.png'; }} />
          </div>

          <h1>{t.title}</h1>

          {loading ? (
            <div className="wifi-loading">{t.loading}</div>
          ) : error ? (
            <div className="wifi-error">
              {t.errorPrefix} {error}
            </div>
          ) : (
            <>
              <div className="wifi-details">
                <div className="wifi-row">
                  <span className="wifi-label">{t.ssidLabel}</span>
                  <span className="wifi-value">{ssid}</span>
                </div>
                <div className="wifi-row">
                  <span className="wifi-label">{t.passwordLabel}</span>
                  <span className="wifi-value">{password}</span>
                </div>
              </div>

              <div className="wifi-qr-container">
                <img 
                  src={`/img/wifi-qr.png?t=${Date.now()}`} 
                  alt="WiFi QR Code" 
                  onError={(e) => e.target.style.display = 'none'}
                />
              </div>
            </>
          )}
        </div>
      </div>
    );
  }
}

export default WiFiInfo;
